local function makeSliderBlock(parent, ypos, blockTitle, lbl1, val1, key1, lbl2, val2, key2)

    local blk = new("Frame",{

        Size=UDim2.new(1,-16,0,122), Position=UDim2.new(0,8,0,ypos),

